def is_balanced_brackets(text):
    stack = []
    pairs = {'(': ')', '[': ']', '{': '}'}
    for c in text:
        if c in pairs:
            stack.append(c)
        elif c in pairs.values():
            if not stack or pairs[stack.pop()] != c:
                return False
    return not stack
